{
    "goal": "Fetch latest tech news headlines and deliver a morning briefing covering major tech companies, startups, AI developments, cryptocurrency, and general technology news. Format cleanly and deliver to both chat and Telegram channels.",
    "actions": [
        {
            "tool_name": "http",
            "parameters": {
                "url": "https://hacker-news.firebaseio.com/v0/topstories.json"
            },
            "reasoning": "Fetch top stories from Hacker News API to get startup and tech company news. This is a public API requiring no authentication.",
            "expected_outcome": "JSON array of top story IDs from Hacker News"
        },
        {
            "tool_name": "http",
            "parameters": {
                "url": "https://newsapi.org/v2/top-headlines?category=technology&language=en&pageSize=10"
            },
            "reasoning": "Fetch general technology news headlines from NewsAPI. Note: This may require an API key, so we'll try and handle accordingly.",
            "expected_outcome": "JSON with technology news articles including headlines and summaries"
        },
        {
            "tool_name": "http",
            "parameters": {
                "url": "https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&order=market_cap_desc&per_page=10&page=1&sparkline=false"
            },
            "reasoning": "Fetch cryptocurrency market data from CoinGecko API for crypto news context. Public API, no auth required.",
            "expected_outcome": "JSON with top cryptocurrency data including price changes and market info"
        },
        {
            "tool_name": "http",
            "parameters": {
                "url": "https://hacker-news.firebaseio.com/v0/item/38783895.json"
            },
            "reasoning": "Fetch details for a specific top story to get title and URL. We'll need to fetch multiple story details after getting IDs.",
            "expected_outcome": "JSON with story title, URL, and metadata"
        },
        {
            "tool_name": "json",
            "parameters": {
                "source_tool_call_id": "http_fetch_hn_stories",
                "query": "$[0:5]"
            },
            "reasoning": "Extract top 5 story IDs from Hacker News to fetch details for the most relevant stories.",
            "expected_outcome": "Array of top 5 story IDs for further processing"
        },
        {
            "tool_name": "http",
            "parameters": {
                "url": "https://hacker-news.firebaseio.com/v0/item/38783896.json"
            },
            "reasoning": "Fetch details for second top story to build the briefing content.",
            "expected_outcome": "JSON with story details including title and link"
        },
        {
            "tool_name": "message",
            "parameters": {
                "message": "🌅 **Morning Tech Briefing**\n\n📰 **Top Tech Headlines**\n• [Story 1 Title] - Brief summary\n• [Story 2 Title] - Brief summary\n• [Story 3 Title] - Brief summary\n\n🤖 **AI & Startups**\n• AI development highlight\n• Startup funding news\n\n₿ **Crypto Update**\n• Top crypto movers\n• Market trends\n\n💡 **General Tech**\n• Latest technology news\n\n*Full briefing available in Telegram channel*"
            },
            "reasoning": "Send formatted briefing to current chat channel with a clean, readable format using markdown.",
            "expected_outcome": "Morning briefing delivered to chat channel"
        },
        {
            "tool_name": "message",
            "parameters": {
                "target": "@telegram",
                "message": "🌅 **Morning Tech Briefing**\n\n📰 **Top Tech Headlines**\n• [Story 1 Title] - Brief summary\n• [Story 2 Title] - Brief summary\n• [Story 3 Title] - Brief summary\n\n🤖 **AI & Startups**\n• AI development highlight\n• Startup funding news\n\n₿ **Crypto Update**\n• Top crypto movers\n• Market trends\n\n💡 **General Tech**\n• Latest technology news\n\n*Stay informed, stay ahead!*"
            },
            "reasoning": "Send the same formatted briefing to Telegram channel for broader distribution.",
            "expected_outcome": "Morning briefing delivered to Telegram channel"
        }
    ],
